import numpy as np
from scipy.stats import spearmanr

def evaluate_single_factor(factor, forwardReturns):
    ic, _ = spearmanr(factor, forwardReturns)
    return {'IC': round(ic, 4), 'IC_sign': 'positive' if ic > 0 else 'negative', 'IC_strength': 'strong' if abs(ic) > 0.05 else ('moderate' if abs(ic) > 0.02 else 'weak')}
